var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다 끝내셨나요, 스승님?","JPN":"師匠、終わりましたか？","ENG":"You done, Master?","TWN":"都結束了嗎，師父？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미리 언질을 듣긴 했지만, 이 정도로 침식체들이 늘어난 걸 보면 정말 상황이 심각하긴 한 모양이네요.","JPN":"聞いてはいましたが、ここまで侵食体が増えてるとは。よほど深刻な状況なんですね。","ENG":"The VP did give us a heads up, but I guess things are getting pretty serious considering the surge in C.O. count.","TWN":"雖然之前就已經聽說了，但侵蝕體竟然增加到這種程度，情況看來非常嚴重。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이래서야 그 조력자라는 분들도 과연 무사하실지 모르겠는데요?","JPN":"これじゃあ助っ人の方々も無事かどうか。","ENG":"I hope those assets are still in one piece.","TWN":"那兩位助手究竟有沒有平安無事呢？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 제자야.","JPN":"なあ、弟子よ。","ENG":"Shiyoon.","TWN":"喂，徒弟。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"왜 그러시죠? 스승님.","JPN":"どうされました、師匠。","ENG":"Yes? Master?","TWN":"師父，怎麼了？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"물어볼 게 있는데......","JPN":"聞きたいことがあるんだが……","ENG":"Let me ask you something...","TWN":"我問你……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너희들이 만난 게...... 정말 그 죽은 리플레이서 간부였나?","JPN":"お前たちが会ったのは……本当に、あの死んだリプレイサー幹部だったのか？","ENG":"The hostile you said you encountered... Was it really the dead Replacer officer?","TWN":"你們見到的真的是克隆集團的幹部嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아아, 그거 말인가요?","JPN":"ああ、そのことですか。","ENG":"Oh, that?","TWN":"啊啊，妳說那個嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 정황상 그렇게 보이긴 했습니다.","JPN":"まあ、状況からはそのように見えました。","ENG":"Yeah, it seemed like it at the time.","TWN":"嗯……照當時的情況來看應該是的。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......물론 보이는 게 다는 아니겠지만요.","JPN":"……もちろん、目に見えるものがすべてではないでしょうけど。","ENG":"Of course, what we saw might not be everything.","TWN":"……當然，眼見不一定為實。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......역시 그렇군.","JPN":"……やはりそうか。","ENG":"I see...","TWN":"……果然是這樣嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"참 신기하죠? 죽은 사람도 휙휙 살려낼 수 있다니......","JPN":"不思議ですよね、死んだ人もさくっと生き返らせるなんて。","ENG":"Fascinating, huh? They can bring back people from the dead like that...","TWN":"真的很不可思議吧？竟然可以讓死人一個個活過來……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"소문만 무성한 구 관리국에도 그런 기술은 없었을 것 같은데요.","JPN":"噂が一人歩きしている旧管理局でさえ、そんな技術は持っていなかったと思いますが。","ENG":"I bet even the Old Administration didn’t have that sort of technology, despite all the hype.","TWN":"就是傳聞頗多的舊管理局，似乎也沒有這種技術。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그게 아니라면......","JPN":"それとも……","ENG":"Or maybe...","TWN":"如果不是這樣的話……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시 이것도 미나 양에게서 추출해 낸 그 신비한 물질의 능력일까요?","JPN":"やっぱりこれも、ミナさんから抽出したというあの神秘的な物質の力なんでしょうか？","ENG":"Could this be from that mysterious substance they extracted from Mina?","TWN":"那這也是從米娜小姐身上提取出來的神秘物質力量囉？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"클리포트 인자라고 했었나......?","JPN":"クリフォト・ファクターでしたっけ？","ENG":"The Qliphoth Factor, or whatever?","TWN":"是叫逆卡巴拉因子嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 스승님을 처음 만났을 때도 그 비슷한 일이 있었죠.","JPN":"そういえば、師匠に初めて会った時も似たようなことがありましたね。","ENG":"Come to think of it, a similar thing happened when I met you for the first time.","TWN":"這麼說來，我第一次見到師父的時候，也發生了類似的事情。"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"예를 들어 제 부모님들에게 일어난 일이라든가......","JPN":"たとえば、僕の両親に起こったこととか……","ENG":"For instance, what happened to my parents...","TWN":"比如說發生在我父母身上的事，還有……"},"stage":{"bg":"CITY_STREET_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};